22:         DRAM     = 0,
23:         GPIO     = 1,
24:         Ethernet = 2,
25:         SPI      = 3,
26:         AES      = 4,    
27:         UART     = 5,   
28:         PLIC     = 6,  
29:         CLINT    = 7, 
30:         PKT      = 8,
31:         ROM2     = 9,
32:         ROM      = 10, 
33:         Debug    = 11
34:     } axi_slaves_t;
35: 
36:     localparam NB_PERIPHERALS = Debug + 1;
37: 
38:     localparam logic[63:0] DebugLength    = 64'h1000;
39:     localparam logic[63:0] ROMLength      = 64'h10000;
40:     localparam logic[63:0] ROM2Length     = 64'h10000;
41:     localparam logic[63:0] PKTLength      = 64'h10000;
42:     localparam logic[63:0] CLINTLength    = 64'hC0000;
43:     localparam logic[63:0] PLICLength     = 64'h3FF_FFFF;
44:     localparam logic[63:0] UARTLength     = 64'h111000; 
45:     localparam logic[63:0] AESLength      = 64'h1000;
46:     localparam logic[63:0] SPILength      = 64'h800000;
47:     localparam logic[63:0] EthernetLength = 64'h10000;
48:     localparam logic[63:0] GPIOLength     = 64'h1000;
49:     localparam logic[63:0] DRAMLength     = 64'h8000000; // 128 MByte of DDR
50:     localparam logic[63:0] SRAMLength     = 64'h1800000;  // 24 MByte of SRAM
