52:     localparam bit GenProtocolChecker = 1'b0;
53: 
54:     typedef enum logic [63:0] {
55:         DebugBase    = 64'h0000_0000,
56:         ROMBase      = 64'h0001_0000,
57:         ROM2Base     = 64'h0021_0000, 
58:         PKTBase      = 64'h0041_0000, 
59:         CLINTBase    = 64'h0200_0000,
60:         PLICBase     = 64'h0C00_0000,
61:         UARTBase     = 64'h1000_0000,
62:         AESBase      = 64'h1010_0000,  
63:         SPIBase      = 64'h2000_0000,
64:         EthernetBase = 64'h3000_0000,
65:         GPIOBase     = 64'h4000_0000,
66:         DRAMBase     = 64'h8000_0000
67:     } soc_bus_start_t;
68: 
69:     // Different AES Key ID's this information is public.
70:     localparam logic[63:0] AESKey_0    = 64'h0000;
71:     localparam logic[63:0] AESKey_1    = 64'h1000;
72:     localparam logic[63:0] AESKey_2    = 64'h2000;
